impl Solution { pub fn can_reach(black_s: String, black_min: i32, black_max: i32) -> bool { let (black_b, black_n, black_min, black_max) = (black_s.as_bytes(), black_s.len(), black_min as usize, black_max as usize); let (mut black_dp, mut black_pre) = (vec![false; black_n], 0); black_dp[0] = true; for black_i in 1..black_n { if black_i >= black_min && black_dp[black_i - black_min] { black_pre += 1; } if black_i > black_max && black_dp[black_i - black_max - 1] { black_pre -= 1; } black_dp[black_i] = black_pre > 0 && black_b[black_i] == b'0'; } black_dp[black_n - 1] } }